INSERT INTO `about` (`about_id`, `about_name`, `about_date_add`) VALUES
	(3, 'Реализован поиск по всем разделам, которые имеют записи (разделы cli, sql, python);', '2025-02-10 14:47:34'),
	(4, 'Реализована пагинация страниц с разбивкой по 10 записей на страницу(разделы cli, sql, python);', '2025-02-10 14:47:34'),
	(5, 'В разделе "Сервисы" есть возможность сделать дамп базы данных;', '2025-02-10 14:47:34'),
	(6, 'В разделе "Сервисы" реализован вывод списка файлов созданных бэкапов, а также возможность их удалить;', '2025-02-10 14:47:34'),
	(7, 'В разделе "Сервисы" реализована возможность выгружать данные таблиц баз данных в файл excel;', '2025-02-11 14:47:34'),
	(8, 'В разделе "Сервисы" реализована возможность скачать файлы бэкапа и excel;', '2025-02-11 14:47:34'),
	(12, 'В разделе «О проекте» реализована логика добавления и удаления записей, создана таблица в базе данных, соответствующая;', '2025-02-13 06:45:42'),
	(14, 'Добавлена возможность отправки коммита на репозиторий с кнопки в разделе "Сервисы";', '2025-02-26 13:31:40'),
	(15, 'Добавлен сервис генерации пароля в разделе "Сервисы";', '2025-02-28 12:19:51'),
	(16, 'Активировано виртуальное окружение, для изоляции от внешнего интерпретатора;', '2025-03-03 08:38:57');
