INSERT INTO `wiki` (`wiki_name`, `wiki_content`, `wiki_date_add`, `wiki_date_edit`, `wiki_id`) VALUES
	('Active Directory ', 'AD. Службы каталогов Microsoft для операционных систем семейства Windows Server. Позволяет администраторам использовать групповые политики для обеспечения единообразия настройки пользовательской рабочей среды, разворачивать программное обеспечение на множестве компьютеров через групповые политики или посредством специальных служб. eXpress поддерживает синхронизацию пользователей с Active Directory, подробнее тут.\r\nДополнительная информация об Active Directiry на сайте Microsoft Learn.', '2026-01-13 11:46:20', '2026-01-13 14:50:20', 2),
	('DNS', 'Domain Name System, система доменных имён. Компьютерная распределённая система для получения информации о доменах. Чаще всего используется для получения IP-адреса по имени хоста (компьютера или устройства).', '2026-01-13 11:55:23', '', 3),
	('WebSocket ', 'Протокол связи поверх TCP-соединения, предназначенный для двустороннего обмена сообщениями между браузером/веб-приложением и веб-сервером, используя постоянное соединение.', '2026-01-13 14:14:17', '', 4),
	('Бэклог ', 'Backlog. Перечень задач или требований продукта, которые необходимо выполнить в будущем.\r\n', '2026-01-13 14:15:04', '', 5),
	('ВКС ', 'Видеоконференцсвязь. Технология интерактивного взаимодействия трёх и более абонентов, обменивающихся аудио и видео (в eXpress для этого есть конференции).', '2026-01-13 14:17:39', '', 6),
	('SOAP (Simple Object Access Protocol) — протокол обмена структурированными сообщениями в распределённой вычислительной среде. Первоначально предназначался в основном для реализации удалённого вызова процедур (RPC), но сейчас используется для обмена произвольными сообщениями в формате XML, а не только для вызова процедур.', 'SOAP', '2026-01-15 08:16:49', '', 7),
	('REST API', 'REST API архитектурный подход, который устанавливает ограничения для API: как они должны быть устроены и какие функции поддерживать. Это позволяет стандартизировать работу программных интерфейсов, сделать их более удобными и производительными.\r\n\r\nСлово REST — акроним от Representational State Transfer, что переводится на русский как «передача состояния представления», «передача репрезентативного состояния» или «передача „самоописываемого“ состояния».', '2026-01-15 08:19:00', '', 8),
	('CI/CD', 'CI/CD (Continuous Integration/Continuous Delivery) – это набор практик, позволяющих автоматизировать сборку, тестирование и развертывание кода. Если говорить проще: это ваш верный робот-помощник, который берет на себя рутинные операции, освобождая время для творчества. ', '2026-01-16 06:47:17', '', 9),
	('CTS', 'Corporate Transport Server - компонент, отвечающий за\r\nмаршрутизацию и хранение передаваемой информации,\r\nадресную книгу и интеграцию с внешними ИС по отноше-\r\nнию к Системе', '2026-03-13 08:47:29', '', 10),
	('DLP', 'Data Leak Prevention − система предотвращения утечки\r\nданных', '2026-03-13 08:52:21', '', 11),
	('АРМ', 'Автоматизированное рабочее место', '2026-03-13 08:52:57', '', 12),
	('КСПД', 'Доверенная корпоративная сеть передачи данных', '2026-03-13 08:58:33', '', 13),
	('NAT', 'Network Address Translation. Механизм преобразования сетевых\r\nадресов транзитных пакетов в сетях IP', '2026-03-13 09:03:00', '', 14),
	('СУБД', 'Система управления базами данных\r\n', '2026-03-13 09:03:28', '', 15),
	('TLS', 'Transport Layer Security. Криптографические протоколы, обеспе-\r\nчивающие защищённую передачу данных между узлами в сети\r\nIP с использованием сертификатов стандарта X.509', '2026-03-13 09:04:59', '', 16),
	('ICAP', 'Internet Content Adaptation Protocol (ICAP) — специализированный протокол, похожий на HTTP, который позволяет устройствам на краю сети передавать входящий контент для специализированного анализа.', '2026-03-13 09:06:40', '', 17),
	('SIEM', 'Security Information and Event Management. Система сбора и анализа событий безопасности.', '2026-03-13 09:07:34', '', 18),
	('KVM', 'Kernel-based Virtual Machine. Среда виртуализации с открытым исходным кодом.', '2026-03-13 09:08:32', '', 19),
	('Host-model — режим эмуляции процессора (CPU) в виртуализации, который описывает CPU гостя подобно хостовому. Это режим, который подбирается так, чтобы модель и набор дополнительных функций виртуального ЦП наиболее точно соответствовали модели и дополнительным функциям ЦП вычислительного сервера, на котором размещена виртуальная машина (полное соответствие не гарантируется). \r\nhabr.com\r\ntechhaps.com\r\nРежим host-model — по умолчанию для гипервизоров KVM и QEMU на хостах x86-64.', 'Host-model', '2026-03-13 09:31:52', '', 20),
	('Host-passthrough', 'Host-passthrough — режим эмуляции процессора (CPU) в виртуализации, при котором виртуальной машине предоставляется виртуальный ЦП такой же модели и с такими же дополнительными функциями, как у ЦП вычислительного сервера, на котором размещена виртуальная машина. \r\nhabr.com\r\ndocs.ispsystem.ru\r\nЭтот режим позволяет:\r\nОбеспечить лучшую производительность — минимизирует затраты на эмуляцию и использует полный набор инструкций хостового ЦП.\r\nОбеспечить совместимость с приложениями, которые требуют продвинутых инструкций ЦП.\r\n \r\nprogrammingetc.hashnode.dev\r\nРежим host-passthrough поддерживается, например, в гипервизорах KVM и QEMU. \r\ndocs.openstack.org\r\nprogrammingetc.hashnode.dev\r\nПринцип работы\r\nВ отличие от режима host-model (по умолчанию), который описывает CPU гостя подобно хостовому, host-passthrough напрямую передаёт характеристики хоста гостю. Это может быть полезно, например: \r\nhabr.com\r\ntechhaps.com\r\nДля вложенной виртуализации — гость может использовать вложенную виртуализацию только при корректном описании CPU в его конфигурации libvirt. Гостю нужен тип CPU, близкий или идентичный физическому CPU хоста.\r\nДля задач, требующих высокой производительности CPU, — например, игр, разработки или рендеринга.\r\n \r\ntechhaps.com\r\nprogrammingetc.hashnode.dev\r\nНастройка\r\nРежим host-passthrough указывается в конфигурации виртуальной машины (ВМ). Например: \r\ndocs.openstack.org\r\ndoc.opensuse.org\r\nВ virt-manager — модель процессора меняется на host-passthrough.\r\nВ virsh — в файле конфигурации ВМ указывается, что CPU гостя настроен как host-passthrough.\r\n \r\nwiki.archlinux.org\r\ndoc.opensuse.org\r\nВажно: режим host-passthrough рекомендуется использовать только если узлы кластера очень однородны — по существу, все узлы используют одну и ту же модель и поколение ЦП. Миграция такой ВМ возможна только на полностью совпадающий процессор. \r\ndocs.openstack.org\r\ndocs.ispsystem.ru\r\nОграничения\r\nНе гарантирует работоспособность горячих миграций виртуальных машин при использовании разных моделей ЦП на вычислительных серверах.\r\nСовместимость между разными хостами при использовании host-passthrough может быть ограничена.\r\nМиграция, сохранение, загрузка и snapshot-операции могут стать недоступны для ВМ, если внутри неё запущена вложенная ВМ. Непредсказуемое поведение может зависеть от версии ядра и реализаций гипервизора.\r\n \r\nhabr.com\r\ntechhaps.com\r\nРекомендуется: режим host-passthrough не рекомендуется для общего использования — его следует использовать только для целей вложенной виртуализации. \r\ndocs.fedoraproject.org', '2026-03-13 09:33:52', '', 21),
	('WSGI', 'WSGI (Web Server Gateway Interface) — это стандарт взаимодействия между веб-сервером и Python-приложением. Он описывает, как сервер должен передавать HTTP-запросы в приложение, а приложение — возвращать ответы обратно. Благодаря WSGI сервер и приложение остаются независимыми: достаточно одного универсального интерфейса, чтобы они «поняли» друг друга. \r\nСсылка: https://selectel.ru/blog/what-is-wsgi/', '2026-03-13 12:11:43', '2026-03-18 10:59:32', 22),
	('Gunicorn ', 'Gunicorn («Green Unicorn») — HTTP-сервер для запуска веб-приложений на Python по протоколу Web Server Gateway Interface (WSGI). Это форк проекта Unicorn для Ruby.', '2026-03-13 12:14:17', '', 23),
	('PIP', 'pip это стандартный менеджер пакетов для языка программирования Python. Он предназначен для установки, обновления и удаления сторонних библиотек и модулей, не входящих в стандартную поставку Python.\r\nhttps://pip.pypa.io/en/stable/', '2026-03-19 06:34:09', '', 24),
	('SQL форматтер', '"https://bi-data.ru/tools/sql/"', '2026-03-19 07:08:23', '', 25),
	('Развертывание python-приложений', '"https://timeweb.cloud/tutorials/python/razvertyvanie-prilozhenij-python"', '2026-03-19 07:58:27', '', 26),
	('Автоинкремент в SQLite', '"https://www.sqlite.org/autoinc.html"', '2026-03-19 12:47:10', '', 27),
	('Markdown', 'Язык разметки Markdown: шпаргалка по синтаксису с примерами. https://skillbox.ru/media/code/yazyk-razmetki-markdown-shpargalka-po-sintaksisu-s-primerami/', '2026-03-19 12:47:43', '', 28);
